1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	interface Step {
17	  op: string;
18	  items?: Array<{ type: string }>;
19	}
20	
21	interface Scenario {
22	  customer: { yearsWithMHPCO: number };
23	  steps: Step[];
24	}
25	
26	function computeComponentPremium(items: Array<{ type: string }>): number {
27	  const counts = new Map<string, number>();
28	  for (const item of items) {
29	    if (COMPONENT_TYPES.has(item.type)) {
30	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
31	    }
32	  }
33	  let premium = 0;
34	  for (const [type, count] of counts) {
35	    if (count === BLOCK_SIZE) {
36	      premium += BLOCK_PREMIUM;
37	    } else {
38	      premium += count * (BASE_PREMIUMS[type] ?? 0);
39	    }
40	  }
41	  return premium;
42	}
43	
44	export function processScenario(scenario: Scenario): { results: unknown[] } {
45	  const results = scenario.steps.map((step) => {
46	    if (step.op === "quote") {
47	      const items = step.items ?? [];
48	      const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
49	      const mainPremium = mainItems.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
50	      const componentPremium = computeComponentPremium(items);
51	      return { premium: mainPremium + componentPremium + PROCESSING_FEE };
52	    }
53	    return {};
54	  });
55	  return { results };
56	}
